import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/dev")!
        case .staging:
            return URL(string: "https://api.example.com/stage")!
        case .production:
            return URL(string: "https://api.example.com/prod")!
        }
    }
}

enum APIError: Error {
    case invalidURL
    case networkError
    case parsingError
}

class NetworkManager {
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func fetchData(completion: @escaping (Result<Data, APIError>) -> Void) {
        guard let url = environment.baseURL.appendingPathComponent("data") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let data = data else {
                completion(.failure(.parsingError))
                return
            }
            
            completion(.success(data))
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Result<Bool, APIError>) -> Void) {
        guard let url = environment.baseURL.appendingPathComponent("auth") else {
            completion(.failure(.invalidURL))
            return
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: parameters, options: [])
        } catch {
            completion(.failure(.parsingError))
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(.networkError))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                completion(.failure(.parsingError))
                return
            }
            
            completion(.success(true))
        }
        
        task.resume()
    }
}